INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('mensionamento das unidades económicas, tendo efeitos positivos na estrutura produtiva, pode autorizar, a requerimento dos interessados entregue na Direcção-Geral dos Impostos até ao fim do mês seguinte ao do registo da fusão na conservatória do registo comercial, que os prejuízos fiscais das sociedades fundidas possam ser deduzidos dos lucros tributáveis na nova sociedade ou da sociedade incorporante até ao fim do período referido no n.º 1 do artigo 46.º, contado do exercício a que os mesmos se reportam, podendo, não obstante, ser fixado no despacho de autorização um plano específico de dedução de modo que os prejuízos a deduzir em cada exercício não ultrapassem determinado limite. 
