INSERT OR IGNORE INTO Articles (text, category_id) VALUES (', S. A., para a Transtejo e para a Sociedade de Transportes Colectivos do Porto - STCP, S. A., a dotação inscrita no capítulo 50 do orçamento do Ministério do Equipamento Social destinada ao financiamento de acções que visem a melhoria da qualidade dos serviços dos transportes colectivos de passageiros, até ao montante de 100000 contos; 
