INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rir verbas inscritas no orçamento do Gabinete do Ministro da Juventude e do Desporto para os orçamentos da Secretaria-Geral e da Inspecção-Geral do Ministério da Juventude e do Desporto, por forma a assegurar o funcionamento destes dois organismos em 2002, assim que as respectivas leis orgânicas entrem em vigor, momento em que a Secretaria-Geral passará também a executar os programas do PIDDAC atribuídos ao Gabinete do Ministro; 
